mapper.select:
SELECT room_id, room_name, capacity, location, has_video, has_phone, amenities, active, created_at FROM platform_v3.rm_room WHERE active = TRUE
AND (room_name ILIKE '%' || #{keyword} || '%' OR location ILIKE '%' || #{keyword} || '%')
AND capacity >= #{minCapacity}
AND has_video = #{hasVideo}
ORDER BY capacity DESC, room_name

SELECT r.room_id, r.room_name, r.capacity, r.location, r.has_video, r.has_phone, r.amenities FROM platform_v3.rm_room r WHERE r.active = TRUE
AND r.capacity >= #{minCapacity}
AND r.has_video = #{hasVideo}
AND NOT EXISTS ( SELECT 1 FROM platform_v3.rm_booking b WHERE b.room_id = r.room_id AND b.status = 'BOOKED' AND b.start_at < #{to}::timestamptz AND b.end_at > #{from}::timestamptz ) ORDER BY r.capacity, r.room_name

SELECT COUNT(*) FROM platform_v3.rm_booking
WHERE room_id = #{roomId}
  AND status = 'BOOKED'
  AND start_at < #{to}::timestamptz
  AND end_at   > #{from}::timestamptz

    AND booking_id <> #{excludeBookingId}

mapper.update:
UPDATE platform_v3.rm_booking
SET status = #{status}
WHERE booking_id = #{bookingId}

UPDATE platform_v3.rm_booking
SET livekit_room = #{livekitRoom}
WHERE booking_id = #{bookingId}
